import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext'; // Import useAuth hook

function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState(''); // State to hold error messages
  const { login, loading } = useAuth(); // Get the login function and loading state from AuthContext
  const navigate = useNavigate();

  const handleLogin = async (e) => { // Make the function async
    e.preventDefault(); // Prevents default form submission (page reload)
    setError(''); // Clear any previous error messages

    try {
      // Call the login function from AuthContext
      await login(email, password); 
      console.log("Login successful. Navigating to /for-you.");
      navigate('/for-you'); // Navigate only AFTER successful authentication
    } catch (err) {
      console.error("Login failed:", err);
      // Display error message to the user from the thrown error
      setError(err.message || 'Failed to log in. Please check your credentials.');
    }
  };

  const styles = {
    loginContainer: {
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      minHeight: '100vh',
      background: '#2196F3',
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", "Roboto", sans-serif',
      position: 'relative',
      overflow: 'hidden',
    },
    backgroundAnimation: {
      position: 'absolute',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      background: `
        radial-gradient(circle at 20% 80%, rgba(120, 119, 198, 0.3) 0%, transparent 50%),
        radial-gradient(circle at 80% 20%, rgba(255, 119, 198, 0.3) 0%, transparent 50%),
        radial-gradient(circle at 40% 40%, rgba(120, 219, 255, 0.2) 0%, transparent 50%)
      `,
    },
    loginCard: {
      display: 'flex',
      backgroundColor: 'rgba(255, 255, 255, 0.95)',
      backdropFilter: 'blur(20px)',
      borderRadius: '24px',
      boxShadow: '0 25px 50px rgba(0, 0, 0, 0.15)',
      overflow: 'hidden',
      width: '1000px',
      maxWidth: '90%',
      minHeight: '600px',
      border: '1px solid rgba(255, 255, 255, 0.2)',
    },
    loginFormSection: {
      flex: 1,
      padding: '50px',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'center',
    },
    graphicSection: {
      flex: 1,
      background: 'linear-gradient(135deg, rgba(102, 126, 234, 0.1) 0%, rgba(118, 75, 162, 0.1) 100%)',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'center',
      alignItems: 'center',
      padding: '40px',
      position: 'relative',
      overflow: 'hidden',
    },
    heading: {
      fontSize: '2.8em',
      color: 'transparent',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      WebkitBackgroundClip: 'text',
      backgroundClip: 'text',
      marginBottom: '40px',
      fontWeight: '700',
      textAlign: 'center',
    },
    form: {
      width: '100%',
      display: 'flex',
      flexDirection: 'column',
      gap: '24px',
    },
    inputGroup: {
      position: 'relative',
    },
    input: {
      padding: '18px 20px 18px 60px',
      border: '2px solid rgba(226, 232, 240, 0.8)',
      borderRadius: '16px',
      fontSize: '1em',
      width: '100%',
      boxSizing: 'border-box',
      transition: 'all 0.3s ease',
      backgroundColor: 'rgba(248, 250, 252, 0.8)',
      fontWeight: '500',
    },
    inputIcon: {
      position: 'absolute',
      left: '20px',
      top: '50%',
      transform: 'translateY(-50%)',
      width: '24px',
      height: '24px',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      borderRadius: '8px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      color: 'white',
      fontSize: '14px',
      fontWeight: 'bold',
    },
    button: {
      background: '#4e54c8',
      color: 'white',
      padding: '18px',
      border: 'none',
      borderRadius: '16px',
      fontSize: '1.1em',
      fontWeight: '600',
      cursor: 'pointer',
      transition: 'all 0.3s ease',
      width: '100%',
      marginTop: '10px',
      boxShadow: '0 8px 25px rgba(102, 126, 234, 0.4)',
      position: 'relative',
      overflow: 'hidden',
    },
    buttonHover: {
      position: 'absolute',
      top: '0',
      left: '-100%',
      width: '100%',
      height: '100%',
      background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.2), transparent)',
      transition: 'left 0.5s',
    },
    registerLink: {
      marginTop: '30px',
      fontSize: '0.95em',
      color: '#718096',
      textAlign: 'center',
    },
    link: {
      color: '#667eea',
      textDecoration: 'none',
      fontWeight: '600',
    },
    userIconContainer: {
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '30px',
    },
    userIcon: {
      width: '120px',
      height: '120px',
      borderRadius: '50%',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontSize: '48px',
      fontWeight: 'bold',
      color: 'white',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      boxShadow: '0 20px 40px rgba(102, 126, 234, 0.4)',
      transition: 'all 0.3s ease',
    },
    userText: {
      fontSize: '1.5em',
      color: '#2D3748',
      fontWeight: '600',
      textAlign: 'center',
      marginTop: '20px',
    },
    userDescription: {
      fontSize: '1em',
      color: '#4A5568',
      textAlign: 'center',
      maxWidth: '400px',
      lineHeight: '1.5',
    },
    floatingOrbs: {
      position: 'absolute',
      width: '100%',
      height: '100%',
      top: 0,
      left: 0,
    },
    orb: {
      position: 'absolute',
      borderRadius: '50%',
      background: 'radial-gradient(circle, rgba(255,255,255,0.8) 0%, rgba(255,255,255,0) 70%)',
      animation: 'float 6s ease-in-out infinite',
    },
    errorMessage: {
        color: '#ff4d4f', // A clear error color
        textAlign: 'center',
        marginTop: '15px',
        fontWeight: '500',
        fontSize: '0.95em',
    }
  };

  const userIcon = {
    icon: '👤'
  };

  const orbs = [
    { size: '120px', top: '10%', left: '10%', animationDelay: '0s' },
    { size: '80px', top: '70%', left: '80%', animationDelay: '2s' },
    { size: '100px', top: '20%', left: '85%', animationDelay: '4s' },
    { size: '90px', top: '80%', left: '15%', animationDelay: '1s' },
  ];

  const animationStyles = `
    @keyframes float {
      0%, 100% { transform: translateY(0px) rotate(0deg); }
      50% { transform: translateY(-20px) rotate(180deg); }
    }
  `;

  return (
    <>
      <style>{animationStyles}</style>
      <div style={styles.loginContainer}>
        <div style={styles.backgroundAnimation} />
        
        <div style={styles.loginCard}>
          <div style={styles.loginFormSection}>
            <h2 style={styles.heading}>FLOW TRACK</h2>
            <form onSubmit={handleLogin} style={styles.form}>
              <div style={styles.inputGroup}>
                <div style={styles.inputIcon}>@</div>
                <input
                  type="email"
                  placeholder="Email Address"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  style={styles.input}
                  onFocus={(e) => {
                    e.target.style.borderColor = '#667eea';
                    e.target.style.boxShadow = '0 0 0 3px rgba(102, 126, 234, 0.1)';
                  }}
                  onBlur={(e) => {
                    e.target.style.borderColor = 'rgba(226, 232, 240, 0.8)';
                    e.target.style.boxShadow = 'none';
                  }}
                />
              </div>
              
              <div style={styles.inputGroup}>
                <div style={styles.inputIcon}>#</div>
                <input
                  type="password"
                  placeholder="Password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                  style={styles.input}
                  onFocus={(e) => {
                    e.target.style.borderColor = '#667eea';
                    e.target.style.boxShadow = '0 0 0 3px rgba(102, 126, 234, 0.1)';
                  }}
                  onBlur={(e) => {
                    e.target.style.borderColor = 'rgba(226, 232, 240, 0.8)';
                    e.target.style.boxShadow = 'none';
                  }}
                />
              </div>
              
              <button 
                type="submit" 
                style={styles.button}
                onMouseOver={(e) => {
                  e.target.style.transform = 'translateY(-3px)';
                  e.target.style.boxShadow = '0 12px 30px rgba(102, 126, 234, 0.5)';
                }}
                onMouseOut={(e) => {
                  e.target.style.transform = 'translateY(0)';
                  e.target.style.boxShadow = '0 8px 25px rgba(102, 126, 234, 0.4)';
                }}
                disabled={loading} // Disable button while login is in progress
              >
                {loading ? 'Signing In...' : 'Sign In'} {/* Dynamic text based on loading state */}
                <div style={styles.buttonHover}></div>
              </button>
              {error && <p style={styles.errorMessage}>{error}</p>} {/* Display error message */}
            </form>
            <p style={styles.registerLink}>
              Don't have an account? <Link to="/register" style={styles.link}>Create Account</Link>
            </p>
          </div>
          
          <div style={styles.graphicSection}>
            <div style={styles.floatingOrbs}>
              {orbs.map((orb, index) => (
                <div
                  key={index}
                  style={{
                    ...styles.orb,
                    width: orb.size,
                    height: orb.size,
                    top: orb.top,
                    left: orb.left,
                    animationDelay: orb.animationDelay,
                  }}
                />
              ))}
            </div>
            
            <div style={styles.userIconContainer}>
              <div 
                style={styles.userIcon}
                onMouseOver={(e) => {
                  e.currentTarget.style.transform = 'scale(1.1)';
                  e.currentTarget.style.boxShadow = '0 25px 50px rgba(102, 126, 234, 0.6)';
                }}
                onMouseOut={(e) => {
                  e.currentTarget.style.transform = 'scale(1)';
                  e.currentTarget.style.boxShadow = '0 20px 40px rgba(102, 126, 234, 0.4)';
                }}
              >
                {userIcon.icon}
              </div>
              <h3 style={styles.userText}>Welcome Back</h3>
              <p style={styles.userDescription}>
                Sign in to access your projects, collaborate with your team, 
                and continue tracking your progress seamlessly.
              </p>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}

export default Login;
